function solve(nums, queries) {
    class FenwickTree {
        constructor(size) {
            this.n = size;
            this.tree = new Array(this.n + 1).fill(0);
        }

        update(index, delta) {
            while (index <= this.n) {
                this.tree[index] += delta;
                index += index & -index;
            }
        }

        query(index) {
            let res = 0;
            while (index > 0) {
                res += this.tree[index];
                index -= index & -index;
            }
            return res;
        }

        rangeQuery(l, r) {
            return this.query(r + 1) - this.query(l);
        }
    }

    function popcount(x) {
        let count = 0;
        while (x) {
            x &= x - 1;
            count++;
        }
        return count;
    }

    function getDepth(x) {
        let depth = 0;
        let current = x;
        while (current !== 1) {
            current = popcount(current);
            depth++;
        }
        return depth;
    }

    const n = nums.length;
    const maxDepth = 64;
    const ft = Array(maxDepth + 1).fill().map(() => new FenwickTree(n));

    const depths = nums.map(x => getDepth(x));

    for (let i = 0; i < n; i++) {
        const d = depths[i];
        ft[d].update(i + 1, 1);
    }

    const answer = [];

    for (const q of queries) {
        if (q[0] === 1) {
            const [_, l, r, k] = q;
            const count = ft[k].rangeQuery(l, r);
            answer.push(count);
        } else {
            const [_, idx, val] = q;
            const oldVal = nums[idx];
            const oldDepth = depths[idx];
            ft[oldDepth].update(idx + 1, -1);
            const newDepth = getDepth(val);
            ft[newDepth].update(idx + 1, 1);
            nums[idx] = val;
            depths[idx] = newDepth;
        }
    }

    return answer;
}

